<!-- 100 chars: the tail word after the expression tag fits, so the fill stays on one line. -->
<li>
	aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa ~{xxxxxxxxxx} cc
</li>

<!-- 101 chars: tsv breaks at the collapsible space before the tail word to hold the line
     <= 100. Prettier keeps the tail on the line and overflows to 101. -->
<li>
	aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa ~{xxxxxxxxxx} cc
</li>
